  from collections import defaultdict
      # Gather objects per subject‑predicate, deduplicate while preserving order
      subj_pred_objs: dict[str, dict[str, list[str]]] = defaultdict(lambda: defaultdict(list))
      for t in triples:
          objs = subj_pred_objs[t.subject][t.predicate]
          if t.object not in objs:
              objs.append(t.object)

      sentences: list[str] = []
      for subj, pred_map in subj_pred_objs.items():
          phrases: list[str] = []
          for pred, objs in pred_map.items():
              generator = phrase_map.get(pred)
              obj_text = " and ".join(objs)
              phrase = generator(obj_text) if generator else f"{pred} {obj_text}"
              phrases.append(phrase)
          if len(phrases) == 1:
              sentences.append(f"{subj} {phrases[0]}.")
          else:
              sentences.append(f"{subj} " + ", ".join(phrases[:-1]) + ", and " + phrases[-1] + ".")
